export const _Str_trim: (a: string) => string = (s: any) => s.trim();
export const _Str_split: { (a: string): (b: string) => string[]; (a: string, b: string): string[]; } = _curry(2, (sep: any, s: any) => s.split(sep));
export const _Str_join: { (a: string): (b: string[]) => string; (a: string, b: string[]): string; } = _curry(2, (sep: any, xs: any) => xs.join(sep));
export const _Str_contains: { (a: string): (b: string) => boolean; (a: string, b: string): boolean; } = _curry(2, (needle: any, s: any) => s.includes(needle));
export const _Str_startsWith: { (a: string): (b: string) => boolean; (a: string, b: string): boolean; } = _curry(2, (p: any, s: any) => s.startsWith(p));
export const _Str_endsWith: { (a: string): (b: string) => boolean; (a: string, b: string): boolean; } = _curry(2, (p: any, s: any) => s.endsWith(p));
export const _Str_slice: { (a: number): (b: number) => (c: string) => string; (a: number): (b: number, c: string) => string; (a: number, b: number): (c: string) => string; (a: number, b: number, c: string): string; } = _curry(3, (start: any, end: any, s: any) => s.slice(start, end));
export const _Str_replace: { (a: string): (b: string) => (c: string) => string; (a: string): (b: string, c: string) => string; (a: string, b: string): (c: string) => string; (a: string, b: string, c: string): string; } = _curry(3, (find: any, repl: any, s: any) => s.replaceAll(find, repl));
export const _Str_get: { (a: number): (b: string) => Option<string>; (a: number, b: string): Option<string>; } = _curry(2, (i: any, s: any) => (i >= 0 && i < s.length ? Some(s[i]) : None));
export const _Str_codeAt: { (a: number): (b: string) => Option<number>; (a: number, b: string): Option<number>; } = _curry(2, (i: any, s: any) => (i >= 0 && i < s.length ? Some(s.charCodeAt(i)) : None));
export const _Str_fromCode: (a: number) => string = (n: any) => String.fromCharCode(n);
export const _Str_chars: (a: string) => string[] = (s: any) => [...s];
export const _Str_toNumber: (a: string) => Option<number> = (s: any) => { const n = Number(s); return Number.isNaN(n) ? None : Some(n); };
